window.__SEA_GLOSSARY__ = [{"term": "Adaptation", "cat": "Ecology", "def": "A feature or behavior that helps a living thing survive in its environment."}, {"term": "Biodiversity", "cat": "Ecology", "def": "The variety of different living things and habitats in an area."}, {"term": "Biome", "cat": "Habitats", "def": "A large region defined by its climate and the community of life adapted to it."}, {"term": "Camouflage", "cat": "Animals", "def": "Colors or patterns that help an animal blend into its surroundings."}, {"term": "Canopy", "cat": "Plants", "def": "The leafy upper layer of a forest formed by the tallest trees."}, {"term": "Carnivore", "cat": "Animals", "def": "An animal that eats other animals."}, {"term": "Climate", "cat": "Habitats", "def": "The usual pattern of temperature and rainfall in a place over many years."}, {"term": "Cold-blooded", "cat": "Animals", "def": "Relying on the surroundings, such as sunlight, to control body temperature."}, {"term": "Conservation", "cat": "Conservation", "def": "Caring for and protecting nature so it stays healthy for the future."}, {"term": "Decomposer", "cat": "Ecology", "def": "A living thing that breaks down dead matter and returns its nutrients to the soil."}, {"term": "Deciduous", "cat": "Plants", "def": "Describing trees that drop their leaves each year, as in temperate forests."}, {"term": "Ecosystem", "cat": "Ecology", "def": "All the living things in an area plus the non-living things they depend on."}, {"term": "Endangered species", "cat": "Conservation", "def": "A species at serious risk of dying out completely."}, {"term": "Erosion", "cat": "Geology", "def": "The wearing away and carrying off of soil or rock by water, wind or ice."}, {"term": "Extinct", "cat": "Conservation", "def": "Describing a species that has died out completely and forever."}, {"term": "Food chain", "cat": "Ecology", "def": "The path of energy as one living thing is eaten by another."}, {"term": "Food web", "cat": "Ecology", "def": "The network of many connected food chains in an ecosystem."}, {"term": "Fossil", "cat": "Geology", "def": "The preserved remains or trace of a living thing from long ago."}, {"term": "Fragmentation", "cat": "Conservation", "def": "The breaking of habitat into smaller, separated pieces."}, {"term": "Fungus", "cat": "Plants", "def": "A living thing, neither plant nor animal, that feeds by breaking matter down."}, {"term": "Germination", "cat": "Plants", "def": "When a seed begins to sprout and grow into a new plant."}, {"term": "Habitat", "cat": "Ecology", "def": "The specific place where a particular plant or animal naturally lives."}, {"term": "Herbivore", "cat": "Animals", "def": "An animal that eats only plants."}, {"term": "Humus", "cat": "Geology", "def": "Dark, decayed plant and animal matter that makes soil rich and holds water."}, {"term": "Igneous rock", "cat": "Geology", "def": "Rock formed when molten magma or lava cools and hardens."}, {"term": "Indicator species", "cat": "Ecology", "def": "A species whose presence reveals the health of its environment."}, {"term": "Invasive species", "cat": "Conservation", "def": "A non-native species that spreads aggressively and harms an ecosystem."}, {"term": "Invertebrate", "cat": "Animals", "def": "An animal without a backbone, such as an insect, spider or worm."}, {"term": "Keystone species", "cat": "Ecology", "def": "A species whose presence has an unusually large effect on its ecosystem."}, {"term": "Larva", "cat": "Animals", "def": "A young animal, like a tadpole or caterpillar, that looks unlike the adult."}, {"term": "Lichen", "cat": "Plants", "def": "A partnership of a fungus and an alga that can grow on bare rock or bark."}, {"term": "Magma", "cat": "Geology", "def": "Hot, molten rock beneath the Earth's surface."}, {"term": "Metamorphic rock", "cat": "Geology", "def": "Rock changed into a new form by heat and pressure, without melting."}, {"term": "Migration", "cat": "Animals", "def": "The seasonal journey some animals make between regions to find food or breed."}, {"term": "Mineral", "cat": "Geology", "def": "A naturally formed solid with a definite makeup and orderly crystal structure."}, {"term": "Native species", "cat": "Conservation", "def": "A species that naturally belongs in a particular region."}, {"term": "Naturalist", "cat": "Field skills", "def": "A person who studies and observes nature in the field."}, {"term": "Niche", "cat": "Ecology", "def": "The particular role and way of life a species has in its ecosystem."}, {"term": "Nocturnal", "cat": "Animals", "def": "Active mainly at night."}, {"term": "Omnivore", "cat": "Animals", "def": "An animal that eats both plants and animals."}, {"term": "Photosynthesis", "cat": "Plants", "def": "How plants use sunlight, water and carbon dioxide to make food and release oxygen."}, {"term": "Pioneer species", "cat": "Ecology", "def": "The first tough species to colonize bare or disturbed ground."}, {"term": "Pollinator", "cat": "Animals", "def": "An animal that moves pollen so plants can make seeds and fruit."}, {"term": "Predator", "cat": "Animals", "def": "An animal that hunts and eats other animals."}, {"term": "Prey", "cat": "Animals", "def": "An animal that is hunted and eaten by another."}, {"term": "Producer", "cat": "Ecology", "def": "A living thing, usually a plant, that makes its own food from sunlight."}, {"term": "Riparian zone", "cat": "Habitats", "def": "The strip of plant life along the banks of a river or stream."}, {"term": "Sediment", "cat": "Geology", "def": "Small pieces of broken-down rock that can pile up and harden into rock."}, {"term": "Sedimentary rock", "cat": "Geology", "def": "Rock formed from layers of sediment pressed and cemented together."}, {"term": "Species", "cat": "Ecology", "def": "A group of living things so alike they can breed and produce similar offspring."}, {"term": "Succession", "cat": "Ecology", "def": "The gradual change in the community of species in an area over time."}, {"term": "Topsoil", "cat": "Geology", "def": "The dark, nutrient-rich upper layer of soil where most plant roots grow."}, {"term": "Vertebrate", "cat": "Animals", "def": "An animal with a backbone, such as a mammal, bird, reptile, amphibian or fish."}, {"term": "Warm-blooded", "cat": "Animals", "def": "Able to keep a steady body temperature even when it is cold outside."}, {"term": "Watershed", "cat": "Habitats", "def": "All the land that drains into a particular river, lake or wetland."}, {"term": "Wetland", "cat": "Habitats", "def": "Land soaked or covered with water at least part of the year."}, {"term": "Weathering", "cat": "Geology", "def": "The breaking down of rock in place by water, ice, plants or chemicals."}, {"term": "Wildlife corridor", "cat": "Conservation", "def": "A protected strip of habitat that lets animals move between larger areas."}];
